var e=[{id:`L2_1`,type:`dialog`,speaker:`NAIEL_SCHOOL_NPC_NULL`,text:{KOREA:`헉헉…`,JPN:`はあはあ……`,ENG:`*Huff* *Huff...*`,TWN:`呼呼…`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_SERIOUS`},C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:`NAIEL_SCHOOL_NPC_NULL`,text:{KOREA:`너, 제법이네.`,JPN:`あんた、やるね。`,ENG:`You're pretty good.`,TWN:`哼，你蠻有兩下子的嘛。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그대도 강하오.`,JPN:`貴殿も強いです。`,ENG:`You are strong as well.`,TWN:`你也蠻強的。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_PRIDE`}}}},{id:`L5_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`허나 그 움직임엔 질서가 없구려.`,JPN:`ですが、その動きには秩序がありません。`,ENG:`However, your movement lacks discipline.`,TWN:`只是動作毫無章法。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`무작정 휘두르기 보다 상대의 빈틈이 드러나길 노리시오.`,JPN:`むやみに振り回すより、相手の隙を見定めて狙ってください。`,ENG:`You should aim for an opening rather than mindlessly swinging your sword.`,TWN:`與其漫無目的地亂揮，建議你可以看準對方露出破綻時再出手。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`NAIEL_SCHOOL_NPC_NULL`,text:{KOREA:`너어…! 네까짓 게 뭘 안다고 이 엘리트님을 가르치려 들어?!`,JPN:`あんた、何を偉そうに……！　このエリート様を指導しようとしてるの！？`,ENG:`Excuse me?! How dare you try to educate an elite like me?!`,TWN:`你…！你算哪根蔥，憑什麼建議我這個菁英？！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_HATE`},C:null,R:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`SNIPER_SL_NULL_NULL`,text:{KOREA:`타깃 확보했습니다.`,JPN:`ターゲットを確保しました。`,ENG:`Target acquired.`,TWN:`發現目標。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_SL_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`TAO_NPC_ACADEMY_NULL`,text:{KOREA:`카운터니까 어딜 노리든 쉽게 죽진 않겠지만, 왠만하면 팔이나 다리를 노려.`,JPN:`カウンターだからどこを狙ってもそう簡単に死なないだろうけど、なるべく腕や足を狙え。`,ENG:`She's a Counter, so it probably won't kill her anyway, but try to aim for her arm or leg.`,TWN:`她是制裁者，不管瞄準哪裡，都不至於會要她的命，不如就瞄準手或腳吧。`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_SL_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`TAO_NPC_ACADEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L12_1`,type:`dialog`,speaker:`SNIPER_SL_NULL_NULL`,text:{KOREA:`움직임이 너무 빨라서 사선에 계속 엉뚱한 녀석이 꼬이는데… 시합이 끝날 때까지 기다릴까요?`,JPN:`動きが早すぎて、射線上にずっと他のやつが入り込みます……試合が終わるまで待ちましょうか？`,ENG:`She's too fast and there's another girl within my line of sight... Do I wait until their battle is over?`,TWN:`目標動作太快，那個人又一直擋住視線…要等到測驗結束嗎？`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_SL_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`TAO_NPC_ACADEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L13_1`,type:`dialog`,speaker:`TAO_NPC_ACADEMY_NULL`,text:{KOREA:`전투에 정신이 팔린 지금이 기회야.`,JPN:`戦闘に夢中になってる今がチャンスだ。`,ENG:`No, this is our chance. When she's distracted by the battle.`,TWN:`趁她現在專注於決鬥中，`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_SL_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`TAO_NPC_ACADEMY_NULL`,face:`UNIT_IDLE`}}}},{id:`L14_1`,type:`dialog`,speaker:`TAO_NPC_ACADEMY_NULL`,text:{KOREA:`그냥 쏴.`,JPN:`撃て。`,ENG:`Just pull the trigger.`,TWN:`開槍！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_SL_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`TAO_NPC_ACADEMY_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L15_1`,type:`dialog`,speaker:`SNIPER_SL_NULL_NULL`,text:{KOREA:`…알겠습니다.`,JPN:`……わかりました。`,ENG:`...Roger.`,TWN:`…是！`},stage:{bg:`CLOSE`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SNIPER_SL_NULL_NULL`,face:`UNIT_IDLE`},R:{char_id:`TAO_NPC_ACADEMY_NULL`,face:`UNIT_SERIOUS`}}}},{id:`L18_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`음?`,JPN:`む？`,ENG:`Mm?`,TWN:`嗯？`},stage:{bg:`CLOSE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`NAIEL_SCHOOL_NPC_NULL`,text:{KOREA:`찾았다! 빈틈…!`,JPN:`見つけた！　隙……！`,ENG:`Gotcha! An opening...!`,TWN:`找到了！破綻…！`},stage:{bg:`CLOSE`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_HATE`},C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};